import React from 'react';
import { Link, graphql } from 'gatsby';

import Layout from '../components/layout';
import Posts from '../components/posts';
import SEO from '../components/seo';

class PaginatedIndexTemplate extends React.Component {
  render() {
    console.log(this.props);
    const posts = this.props.data.allMarkdownRemark.edges.filter(({ node }) =>
      this.props.pageContext.postSlugs.includes(node.fields.slug)
    );
    const siteTitle = this.props.data.site.siteMetadata.title;
    const { previousPage, nextPage, pageNumber } = this.props.pageContext;

    return (
      <Layout location={this.props.location} title={siteTitle}>
        <SEO title={`Page ${pageNumber} | Blog`}></SEO>
        <Posts posts={posts} />

        <ul
          style={{
            display: `flex`,
            flexWrap: `wrap`,
            justifyContent: `space-between`,
            listStyle: `none`,
            padding: 0,
          }}
        >
          <li>
            {previousPage && (
              <Link to={previousPage} rel="prev">
                ← Newer
              </Link>
            )}
          </li>
          <li>
            {nextPage && (
              <Link to={nextPage} rel="next">
                Older →
              </Link>
            )}
          </li>
        </ul>
      </Layout>
    );
  }
}

export default PaginatedIndexTemplate;

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      edges {
        node {
          excerpt
          fields {
            slug
          }
          frontmatter {
            date: date(formatString: "D MMMM YYYY")
            pathDate: date(formatString: "YYYY/MM")
            slug
            title
            description
            draft
          }
        }
      }
    }
  }
`;
